blocks.content:
queries
    .flatMapLatest { query -> repository.search(query) }
    .buffer(capacity = 1)
    .collectLatest { result -> render(result) }

files.asFlow()
    .flatMapConcat { file -> uploader.uploadAsFlow(file) }
    .collect { progress -> updateProgress(progress) }

ids.asFlow()
    .flatMapMerge(concurrency = 4) { id ->
        flow { emit(api.loadDetail(id)) }
    }
    .toList()

queryFlow
    .map(String::trim)
    .filter { it.length >= 2 }
    .flatMapLatest { query -> repository.search(query) }
    .collect { result -> reduce(result) }

combine(query, selectedCity, jobs) { q, city, items ->
    items.filter { job ->
        job.title.contains(q, ignoreCase = true) && job.city == city
    }
}.distinctUntilChanged()

merge(manualRefresh, retryRefresh, connectivityRefresh)
    .onEach { refreshRepository() }
    .launchIn(viewModelScope)

repository.pages()
    .buffer(capacity = 1)
    .map { page -> parse(page) }
    .collect { parsed -> save(parsed) }

downloadProgress
    .conflate()
    .collect { percent -> renderProgress(percent) }

uiState.collectLatest { state ->
    renderExpensivePreview(state)
}

flow { emit(api.loadJobs()) }
    .retryWhen { cause, attempt ->
        val retryable = cause is IOException && attempt < 3
        if (retryable) delay(500L * (1L shl attempt.toInt()))
        retryable
    }

events.scan(ChatState()) { state, event ->
    reduce(state, event)
}.distinctUntilChanged()

data class SearchCriteria(val query: String, val cityId: String?)

private val query = MutableStateFlow("")
private val cityId = MutableStateFlow<String?>(null)

val state: StateFlow<SearchUiState> = combine(query, cityId) { q, city ->
    SearchCriteria(q.trim(), city)
}
    .filter { it.query.length >= 2 }
    .distinctUntilChanged()
    .flatMapLatest { criteria ->
        repository.search(criteria)
            .map<SearchResult, SearchUiState> { SearchUiState.Content(it.items) }
            .onStart { emit(SearchUiState.Loading(criteria)) }
            .retryWhen { cause, attempt ->
                val retryable = cause is IOException && attempt < 2
                if (retryable) delay(300L * (attempt + 1))
                retryable
            }
            .catch { error -> emit(SearchUiState.Error(mapError(error))) }
    }
    .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5_000), SearchUiState.Idle)
